func genStatefulSet(opts Options) *appsv1.StatefulSet {
	switch {
	case opts.Roles == RoleKube && opts.Updater == false && opts.HighAvailability == false:
		return genStatefulSetKubeUpdaterDisabledHADisabled(opts)
	case opts.Roles == RoleKube && opts.Updater == false && opts.HighAvailability == true:
		return genStatefulSetKubeUpdaterDisabledHAEnabled(opts)
	case opts.Roles == RoleKube && opts.Updater == true && opts.HighAvailability == false:
		return genStatefulSetKubeUpdaterEnabledHADisabled(opts)
	case opts.Roles == RoleKube && opts.Updater == true && opts.HighAvailability == true:
		return genStatefulSetKubeUpdaterEnabledHAEnabled(opts)
	case opts.Roles == RoleKubeAppDiscovery && opts.Updater == false && opts.HighAvailability == false:
		return genStatefulSetKubeAppDiscoveryUpdaterDisabledHADisabled(opts)
	case opts.Roles == RoleKubeAppDiscovery && opts.Updater == false && opts.HighAvailability == true:
		return genStatefulSetKubeAppDiscoveryUpdaterDisabledHAEnabled(opts)
	case opts.Roles == RoleKubeAppDiscovery && opts.Updater == true && opts.HighAvailability == false:
		return genStatefulSetKubeAppDiscoveryUpdaterEnabledHADisabled(opts)
	case opts.Roles == RoleKubeAppDiscovery && opts.Updater == true && opts.HighAvailability == true:
		return genStatefulSetKubeAppDiscoveryUpdaterEnabledHAEnabled(opts)
	}
	panic("genStatefulSet: no rendered variant for the given Options")
}
